const fs = require('fs');
const input = $input.first().json;
const body = input.body || input;

// Determine newsletter type
// 'board' = EAF Board Newsletter (monthly)
// 'market' = FP Market Newsletter (quarterly/milestone)
// 'both' = generate both
const type = String(body.type || body.newsletter || 'board');
const milestone = String(body.milestone || '');
const source = String(body.source || 'manual');

// Load KAI_Context.json
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }

const entities = ctx.entities || {};
const founder = ctx.founder || {};
const tech = ctx.technology || {};
const revenue = ctx.revenue_targets || {};

// Load latest Iris compliance report
let irisReport = 'No recent Iris report found.';
try {
  const irisDir = '/data/Aidan_Outputs/Iris/';
  const irisFiles = fs.readdirSync(irisDir).filter(function(f) { return f.endsWith('.txt'); }).sort().reverse();
  if (irisFiles.length > 0) {
    irisReport = fs.readFileSync(irisDir + irisFiles[0], 'utf8').substring(0, 2000);
  }
} catch(e) { irisReport = 'Iris report unavailable.'; }

// Load latest Scout grant report
let scoutReport = 'No recent Scout grant report found.';
try {
  const scoutDir = '/data/Maryland_Grants/';
  const scoutFiles = fs.readdirSync(scoutDir).filter(function(f) { return f.endsWith('.txt'); }).sort().reverse();
  if (scoutFiles.length > 0) {
    scoutReport = fs.readFileSync(scoutDir + scoutFiles[0], 'utf8').substring(0, 2000);
  }
} catch(e) { scoutReport = 'Scout report unavailable.'; }

// Load latest Jordan grant analysis
let jordanReport = 'No recent Jordan report found.';
try {
  const jordanDir = '/data/Aidan_Outputs/Jordan/';
  const jordanFiles = fs.readdirSync(jordanDir).filter(function(f) { return f.endsWith('.txt'); }).sort().reverse();
  if (jordanFiles.length > 0) {
    jordanReport = fs.readFileSync(jordanDir + jordanFiles[0], 'utf8').substring(0, 2000);
  }
} catch(e) { jordanReport = 'Jordan report unavailable.'; }

// Get active deadlines
const activeDeadlines = (ctx.deadlines || []).filter(function(d) {
  const st = (d.status || '').toUpperCase();
  return st !== 'FILED' && st !== 'COMPLETE' && st !== 'EXEMPT';
});

const month = new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric', timeZone: 'America/New_York' });

return [{ json: {
  type: type,
  milestone: milestone,
  source: source,
  month: month,
  ctx: ctx,
  entities: entities,
  founder: founder,
  tech: tech,
  revenue: revenue,
  irisReport: irisReport,
  scoutReport: scoutReport,
  jordanReport: jordanReport,
  activeDeadlines: activeDeadlines,
  timestamp: new Date().toISOString()
}}];

const https = require('https');
const input = $input.first().json;

if (input.type !== 'board' && input.type !== 'both') {
  const out = {};
  const keys = Object.keys(input);
  for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
  out.boardDraft = null;
  out.boardSkipped = true;
  return [{ json: out }];
}

const founder = input.founder || {};
const entities = input.entities || {};
const activeDeadlines = input.activeDeadlines || [];

const deadlineList = activeDeadlines.slice(0, 10).map(function(d) {
  const today = new Date();
  const due = new Date(d.date);
  const days = Math.ceil((due - today) / (1000 * 60 * 60 * 24));
  return d.item + ' | Due: ' + d.date + ' | ' + (days < 0 ? 'OVERDUE' : days + 'd') + ' | ' + (d.entity || '') + ' | Owner: ' + (d.owner || 'Kevin');
}).join('\n');

const systemMessage = 'You are Sage, Strategic Narrative Agent for KAI-Netics. Draft the EAF Board Newsletter. Tone: formal, transparent, board-appropriate. No marketing language. Document facts, flag risks, surface decisions needed. Maximum 2 pages. This is a legal governance document.';

const userMessage = 'Draft the EAF Board Monthly Newsletter for ' + input.month + '.\n\n' +
  'ORGANIZATION: ' + (entities.EAF && entities.EAF.name ? entities.EAF.name : 'KAI-Netics EAF') + '\n' +
  'EIN: ' + (entities.EAF && entities.EAF.ein ? entities.EAF.ein : '41-4820296') + '\n' +
  'STATUS: ' + (entities.EAF && entities.EAF.status ? entities.EAF.status : '') + '\n' +
  'FOUNDER: ' + (founder.name || 'Kevin Alexander Smith') + '\n\n' +
  'ACTIVE COMPLIANCE DEADLINES:\n' + deadlineList + '\n\n' +
  'LATEST IRIS COMPLIANCE REPORT (excerpt):\n' + input.irisReport + '\n\n' +
  'LATEST GRANT INTELLIGENCE (Scout excerpt):\n' + input.scoutReport + '\n\n' +
  'LATEST GRANT ANALYSIS (Jordan excerpt):\n' + input.jordanReport + '\n\n' +
  'Use this EXACT template structure:\n\n' +
  'EAF BOARD NEWSLETTER\n' +
  'KAI-Netics Equity & Autonomy Foundry, Inc. | ' + input.month + '\n' +
  'Prepared by: Kevin Alexander Smith, Founder & Resident Agent\n' +
  'Distribution: James L. Scott, Esq. | Keith Millard | Maurice Ellis\n\n' +
  '1. MISSION PULSE\n[What did EAF accomplish this month? Be concrete. If nothing, say so honestly.]\n\n' +
  '2. CAKO PROGRAM STATUS\n[Cohort 1 status, curriculum, recruitment, timeline]\n\n' +
  '3. GRANT & COMPLIANCE STATUS\n[IRS Form 1023 status, EARN Maryland, CDBG, compliance flags from Iris, any 21-day items]\n\n' +
  '4. FINANCIAL SUMMARY\n[Grants received, donations, operating expenses, cash position — use $0 if not yet active, document it]\n\n' +
  '5. TALENT PIPELINE AGREEMENT STATUS\n[EAF-to-FP interactions, funds transferred FP to EAF: None, funds transferred EAF to FP: None]\n\n' +
  '6. UPCOMING 30-DAY ACTIONS\n[What board should expect, any votes needed, signatures required]\n\n' +
  '7. ECOSYSTEM INTELLIGENCE HIGHLIGHTS\n[3 bullets from Scout/Jordan on grant opportunities or policy changes relevant to EAF]\n\n' +
  'Questions: kas@kevin-llc.com | 443.257.6836\n' +
  'Next newsletter: 1st of next month';

const requestBody = JSON.stringify({
  model: 'claude-opus-4-6',
  max_tokens: 3000,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});

const result = await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: 'api.anthropic.com',
    port: 443,
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': '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',
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  }, function(res) {
    let d = '';
    res.on('data', function(c) { d += c; });
    res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let boardDraft = '';
try { boardDraft = JSON.parse(result.body).content[0].text || 'Draft generation failed.'; } catch(e) { boardDraft = result.body.substring(0, 500); }

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.boardDraft = boardDraft;
out.boardSkipped = false;
return [{ json: out }];

const https = require('https');
const input = $input.first().json;

if (input.type !== 'market' && input.type !== 'both') {
  const out = {};
  const keys = Object.keys(input);
  for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
  out.marketDraft = null;
  out.marketSkipped = true;
  return [{ json: out }];
}

const founder = input.founder || {};
const revenue = input.revenue || {};
const milestone = input.milestone || '';

const systemMessage = 'You are Sage, Strategic Narrative Agent for KAI-Netics. Draft the FP Market Newsletter. Tone: confident, momentum-forward, concise. External-facing — no internal financials, no EIN, no entity structure details. Think: what would make a procurement VP or investor feel good about this company? Maximum 1 page.';

const userMessage = 'Draft the KAI-Netics FP Market Newsletter for ' + input.month + '.\n\n' +
  'FOUNDER: ' + (founder.name || 'Kevin Alexander Smith') + '\n' +
  'CREDENTIALS: ' + (founder.credentials || []).join(', ') + '\n' +
  'REVENUE TARGETS: Y1 ' + (revenue.year1_total || '') + ' | Y2 ' + (revenue.year2_total || '') + ' | Y3 ' + (revenue.year3_total || '') + '\n' +
  (milestone ? 'MILESTONE TRIGGER: ' + milestone + '\n' : '') + '\n' +
  'LATEST GRANT INTEL (Scout excerpt):\n' + input.scoutReport + '\n\n' +
  'Use this EXACT template structure:\n\n' +
  'KAI-NETICS UPDATE | ' + input.month + '\n' +
  'Drone 3PL for Maryland\'s Medical & Community Supply Chain\n\n' +
  'WHAT WE DEPLOYED\n[What did KAI-Netics fly, contract, or launch? If nothing yet: describe what was built this month]\n\n' +
  'THE CURN STORY\n[1 paragraph on CURN/UROC progress, Baltimore endpoint, or corridor development]\n\n' +
  'GREEN COLLAR SPOTLIGHT\n[EAF/CAKO update for external audience — community impact focus]\n\n' +
  'PARTNERSHIP HIGHLIGHTS\n[New POC agreements, LOIs, ecosystem relationships — or pipeline conversations if none signed]\n\n' +
  'WHAT\'S NEXT\n[Next milestone. One sentence.]\n\n' +
  'THE ASK\n[One specific call to action — supply chain VP intro, 20-min meeting, etc.]\n\n' +
  'Kevin Alexander Smith | kas@kevin-llc.com | 443.257.6836 | kevin-llc.com\n' +
  'FAA Part 107 Certified | MEIA Phase 2 Cohort | UMGC Student | MWVOB';

const requestBody = JSON.stringify({
  model: 'claude-opus-4-6',
  max_tokens: 2000,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});

const result = await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: 'api.anthropic.com',
    port: 443,
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': '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',
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  }, function(res) {
    let d = '';
    res.on('data', function(c) { d += c; });
    res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let marketDraft = '';
try { marketDraft = JSON.parse(result.body).content[0].text || 'Draft generation failed.'; } catch(e) { marketDraft = result.body.substring(0, 500); }

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.marketDraft = marketDraft;
out.marketSkipped = false;
return [{ json: out }];

const fs = require('fs');
const input = $input.first().json;

const timestamp = new Date().toISOString();
const safeTime = timestamp.split(':').join('-').split('.').join('-');

fs.mkdirSync('/data/Aidan_Outputs/Sage', { recursive: true });

let savedFiles = [];
let boardDraft = input.boardDraft || null;
let marketDraft = input.marketDraft || null;

if (boardDraft) {
  const boardPath = '/data/Aidan_Outputs/Sage/Board_Newsletter_' + safeTime + '.txt';
  fs.writeFileSync(boardPath, boardDraft, 'utf8');
  savedFiles.push({ type: 'board', path: boardPath });
}

if (marketDraft) {
  const marketPath = '/data/Aidan_Outputs/Sage/Market_Newsletter_' + safeTime + '.txt';
  fs.writeFileSync(marketPath, marketDraft, 'utf8');
  savedFiles.push({ type: 'market', path: marketPath });
}

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.savedFiles = savedFiles;
out.timestamp = timestamp;
return [{ json: out }];

const http = require('http');
const input = $input.first().json;

const savedFiles = input.savedFiles || [];
const boardDraft = input.boardDraft;
const marketDraft = input.marketDraft;

let whatsappMsg = 'SAGE NEWSLETTER DRAFTS READY\n\n';

if (boardDraft && !input.boardSkipped) {
  whatsappMsg += 'EAF BOARD NEWSLETTER (' + input.month + ')\n';
  whatsappMsg += 'Status: DRAFT READY for Kevin review\n';
  const boardFile = savedFiles.find(function(f) { return f.type === 'board'; });
  if (boardFile) { whatsappMsg += 'File: ' + boardFile.path + '\n'; }
  whatsappMsg += '\nReply: SAGE SEND BOARD to approve and send\n\n';
}

if (marketDraft && !input.marketSkipped) {
  whatsappMsg += 'FP MARKET NEWSLETTER (' + input.month + ')\n';
  whatsappMsg += 'Status: DRAFT READY for Kevin review\n';
  const marketFile = savedFiles.find(function(f) { return f.type === 'market'; });
  if (marketFile) { whatsappMsg += 'File: ' + marketFile.path + '\n'; }
  whatsappMsg += '\nReply: SAGE SEND MARKET to approve and send';
}

if (!boardDraft && !marketDraft) {
  whatsappMsg += 'No drafts generated. Check type parameter.';
}

// Send WhatsApp alert
const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: whatsappMsg } });
const opts = {
  hostname: 'host.docker.internal', port: 8081,
  path: '/message/sendText/Aidan', method: 'POST',
  headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) }
};
await new Promise(function(r) {
  const req = http.request(opts, function(res) { res.on('data', function(){}); res.on('end', r); });
  req.on('error', r); req.write(msgBody); req.end();
});

// Send board draft preview (first 800 chars)
if (boardDraft && !input.boardSkipped) {
  await new Promise(function(r) { setTimeout(r, 1500); });
  const preview = 'BOARD NEWSLETTER PREVIEW:\n\n' + boardDraft.substring(0, 800) + '\n\n[Full draft saved to disk]';
  const previewBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: preview } });
  const previewOpts = {
    hostname: 'host.docker.internal', port: 8081,
    path: '/message/sendText/Aidan', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(previewBody) }
  };
  await new Promise(function(r) {
    const req = http.request(previewOpts, function(res) { res.on('data', function(){}); res.on('end', r); });
    req.on('error', r); req.write(previewBody); req.end();
  });
}

return [{ json: {
  success: true,
  agent: 'Sage',
  type: input.type,
  boardDrafted: !!boardDraft,
  marketDrafted: !!marketDraft,
  savedFiles: savedFiles
}}];
